//出口参数:无
//---------------------------------------------------------------------------------------------------------------------------------
void Write_8bit_1(uint8_t dat)
{
	uint8_t i, com;
	com = 0x80;
	AD9910_SCK1_Clr;
	Delay_ns(10);
	for(i = 0; i < 8; i++)
	{
		if(dat & com) AD9910_SDI1_Set; else AD9910_SDI1_Clr;
		Delay_ns(10);
		AD9910_SCK1_Set;
		Delay_ns(10);
		com = com >> 1;
		AD9910_SCK1_Clr;
		Delay_ns(10);
	}
}

//---------------------------------------------------------------------------------------------------------------------------------
//函数名称:void Write_32bit(uint32_t dat)	
//函数功能:AD9910串行口写入数据
//入口参数:dat      32位数据														
//出口参数:无
//---------------------------------------------------------------------------------------------------------------------------------
void Write_32bit_1(uint32_t dat)
{
	uint8_t i;
	uint32_t com;
	com = 0x80000000;
	AD9910_SCK1_Clr;
	Delay_ns(10);
	for(i = 0; i < 32; i++)
	{
		if(dat & com) AD9910_SDI1_Set; else AD9910_SDI1_Clr;
		Delay_ns(10);
		AD9910_SCK1_Set;
		Delay_ns(10);
		com = com >> 1;
		AD9910_SCK1_Clr;
		Delay_ns(10);
	}
}
//---------------------------------------------------------------------------------------------------------------------------------
//函数名称:void AD9910_Init(void)
//函数功能:AD9910时钟的设置和辅助DAC设置 以及AD9910复位
//入口参数:无
//出口参数:无
//---------------------------------------------------------------------------------------------------------------------------------
void AD9910_Init_1(void)																							 
{
	int j;
	AD9910_MRT1_Set;																	// MRT置1
	AD9910_MRT1_Clr;																	// MRT置0     复位AD9910
	
	AD9910_CSN1_Clr;																	// CSN置0			开片选
	Write_8bit_1(0x02);																// 选择0x02地址            CFR3寄存器写入数据		CFR3是控制时钟倍频之类的寄存器   
	for(j=0;j<4;j++)
	{
		Write_8bit_1(CFR3[j]);
	}
	AD9910_CSN1_Set;																	// CSN置1			关片选
	Delay_ns (10);
	
	AD9910_CSN1_Clr;																	// CSN置0			开片选
	Write_8bit_1(0x03);																// 选择0x03地址            辅助DAC控制写入数据	 控制DAC输出的幅度														
	for(j=0;j<4;j++)
	{
		Write_8bit_1(Assist_DAC[j]);
	}
	AD9910_CSN1_Set;																	// CSN置1			关片选
	
	Delay_ns (10);
	AD9910_IUP1_Clr;																	// 更新AD9910输出
	Delay_ns (10);
	AD9910_IUP1_Set;
	Delay_ns (10);
	AD9910_IUP1_Clr;
}
//---------------------------------------------------------------------------------------------------------------------------------
//函数名称:void AD9910_Singal_Profile_Init(void)
