//---------------------------------------------------------------------------------------------------------------------------------
//函数名称:void AD9910_DRG_Amp_Set( uint32_t upper_limit , uint32_t lower_limit ,uint32_t dec_step , uint32_t inc_step , uint16_t neg_rate ,uint16_t pos_rate)
//函数功能:AD9910的DRG设置------------------幅度
//入口参数:		upper_limit										上限幅度							0x00000000-----0xFFFFFC00				幅度值取高14位
//						lower_limit										下限幅度							0x00000000-----0xFFFFFC00      (上限幅度要大于下限幅度)
//						dec_step											幅度加步进						0x00000000-----0xFFFFFC00							
//						inc_step											幅度减步进						0x00000000-----0xFFFFFC00
//						neg_rate											幅度加的速率(时间)		0x0000----0xffff			  
//						pos_rate											幅度减的速率(时间)		0x0000----0xffff
//出口参数:无
//---------------------------------------------------------------------------------------------------------------------------------
void AD9910_DRG_Amp_Set_1( uint32_t upper_limit , uint32_t lower_limit ,uint32_t dec_step , uint32_t inc_step , uint16_t neg_rate ,uint16_t pos_rate)
{
int i;
	uint32_t upper_temp , lower_temp ,dec_temp, inc_temp;
	uint16_t neg_rate_temp , pos_rate_temp;
	
	upper_temp			=			upper_limit ;		
	lower_temp			=			lower_limit;
		dec_temp  		=			dec_step;
		inc_temp  		=			inc_step;
	neg_rate_temp		=  		neg_rate;																					// 时间
	pos_rate_temp		=  		pos_rate;
	
																								//将上限下限幅度、幅度加减步进、幅度加减速率写入数组，后写入相应的寄存器
	DRL[7]=0;
	DRL[6]=0;
	DRL[5]=(uint8_t)(lower_temp<<2);
	DRL[4]=(uint8_t)(lower_temp>>6);
	DRL[3]=0;
	DRL[2]=0;
	DRL[1]=(upper_temp<<2);
	DRL[0]=(upper_temp>>6);
	
	DRS[7]=0;
	DRS[6]=0;
	DRS[5]=(uint8_t)(inc_temp<<2);
	DRS[4]=(uint8_t)(inc_temp>>6);
	DRS[3]=0;
	DRS[2]=0;
	DRS[1]=(uint8_t)(dec_temp<<2);
	DRS[0]=(uint8_t)(dec_temp>>6);

	
	DRR[3]=(uint8_t) pos_rate_temp;
	DRR[2]=(uint8_t)(pos_rate_temp>>8);
	DRR[1]=(uint8_t) neg_rate_temp;
	DRR[0]=(uint8_t)(neg_rate_temp>>8);
	
	AD9910_CSN1_Clr;												
	Write_8bit_1(0x0B);																												// 将DRL(数字斜坡限值)写入 0x0B
	for(i=0;i<8;i++)
	{
		Write_8bit_1(DRL[i]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	
	AD9910_CSN1_Clr;												
	Write_8bit_1(0x0C);																												// 将DRS(数字斜坡步长)写入 0x0C
	for(i=0;i<8;i++)
	{
		Write_8bit_1(DRS[i]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	
	AD9910_CSN1_Clr;												
	Write_8bit_1(0x0D);																												// 将DRR(数字斜坡速率)写入 0x0D
	for(i=0;i<4;i++)
	{
		Write_8bit_1(DRR[i]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	
	AD9910_IUP1_Clr;																													// 更新AD9910
	Delay_ns (10);
	AD9910_IUP1_Set;
	Delay_ns (10);
	AD9910_IUP1_Clr;
}

//---------------------------------------------------------------------------------------------------------------------------------
//函数名称:void AD9910_DRG_Pha_Init(void)
//函数功能:AD9910的DRG初始化------------------相位
//入口参数:无
//出口参数:无
//---------------------------------------------------------------------------------------------------------------------------------
void AD9910_DRG_Pha_Init_1(void)
{
	uint8_t CFR1[]={0x00,0x40,0x00,0x00};																// 使能AD9910反Sinc滤波                             				
	uint8_t CFR2[]={0x01,0x58,0x08,0x20};																// SYNC_CLK使能，数字斜坡使能	  CFR2[21:20]= 01   选择控制参数为相位
	int j;
	
	AD9910_CSN1_Clr;
	Write_8bit_1(0x00);																								// 将CFR1写入其地址0x00
	for(j=0;j<4;j++)
	{
		Write_8bit_1(CFR1[j]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	
	
	AD9910_CSN1_Clr;
	Write_8bit_1(0x01);																								// 将CFR2写入其地址0x01
	for(j=0;j<4;j++)
	{
		Write_8bit_1(CFR2[j]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	
	
	AD9910_IUP1_Clr;																									// 更新AD9910
	Delay_ns (10);
	AD9910_IUP1_Set;
	Delay_ns (10);
	AD9910_IUP1_Clr;
}

//---------------------------------------------------------------------------------------------------------------------------------
//函数名称:void AD9910_DRG_Pha_Set( uint32_t upper_limit , uint32_t lower_limit ,uint32_t dec_step , uint32_t inc_step , uint16_t neg_rate ,uint16_t pos_rate)
//函数功能:AD9910的DRG设置------------------相位
//入口参数:		upper_limit										上限相位							0~360°
//						lower_limit										下限相位							0~360°      (上限频率要大于下限频率)
//						dec_step											相位加步进						0~360°							
//						inc_step											相位减步进						0~360°
//						neg_rate											相位加的速率(时间)		0x0000----0xffff			  
//						pos_rate											相位减的速率(时间)		0x0000----0xffff
//出口参数:无
//---------------------------------------------------------------------------------------------------------------------------------
void AD9910_DRG_Pha_Set_1( uint32_t upper_limit , uint32_t lower_limit ,uint32_t dec_step , uint32_t inc_step , uint16_t neg_rate ,uint16_t pos_rate)
{
	int i;
	uint32_t upper_temp , lower_temp ,dec_temp, inc_temp;               
	uint16_t neg_rate_temp , pos_rate_temp;
	
	upper_temp			=			(uint32_t)upper_limit*182.04;											// 182.044=2^16/360  根据芯片手册的公式
	lower_temp			=			(uint32_t)lower_limit*182.04;
		dec_temp  		=			(uint32_t)dec_step*182.04;
		inc_temp  		=			(uint32_t)inc_step*182.04;
	
	upper_temp=upper_temp<<16;
	lower_temp=lower_temp<<16;
	dec_temp=dec_temp<<16;
	inc_temp=inc_temp<<16;
	neg_rate_temp		=  		neg_rate;																					// 时间
	pos_rate_temp		=  		pos_rate;
	
	DRL[7]=(uint8_t) lower_temp;
	DRL[6]=(uint8_t)(lower_temp>>8);																							//将上限下限幅度、幅度加减步进、幅度加减速率写入数组，后写入相应的寄存器

	DRL[3]=(uint8_t) upper_temp;
	DRL[2]=(uint8_t)(upper_temp>>8);

	
	DRS[7]=(uint8_t) inc_temp;
	DRS[6]=(uint8_t)(inc_temp>>8);
;
	DRS[3]=(uint8_t) dec_temp;
	DRS[2]=(uint8_t)(dec_temp>>8);

	
	DRR[3]=(uint8_t) pos_rate_temp;
	DRR[2]=(uint8_t)(pos_rate_temp>>8);
	DRR[1]=(uint8_t) neg_rate_temp;
	DRR[0]=(uint8_t)(neg_rate_temp>>8);
	
	AD9910_CSN1_Clr;												
	Write_8bit_1(0x0B);																												// 将DRL(数字斜坡限值)写入 0x0B
	for(i=0;i<8;i++)
	{
		Write_8bit_1(DRL[i]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	
	AD9910_CSN1_Clr;												
	Write_8bit_1(0x0C);																												// 将DRS(数字斜坡步长)写入 0x0C
	for(i=0;i<8;i++)
	{
		Write_8bit_1(DRS[i]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	
	AD9910_CSN1_Clr;												
	Write_8bit_1(0x0D);																												// 将DRR(数字斜坡速率)写入 0x0D
	for(i=0;i<4;i++)
	{
		Write_8bit_1(DRR[i]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	
	AD9910_IUP1_Clr;																													// 更新AD9910
	Delay_ns (10);
	AD9910_IUP1_Set;
	Delay_ns (10);
	AD9910_IUP1_Clr;
}

//---------------------------------------------------------------------------------------------------------------------------------
//函数名称:void AD9910_RAM_Init(void)
//函数功能:将CFR1和CFR2恢复默认值
//入口参数:无
//出口参数:无
//---------------------------------------------------------------------------------------------------------------------------------
void AD9910_RAM_Init_1(void)
{
	int j;
	
	uint8_t CFR1[]={0x00,0x40,0x00,0x00};
	uint8_t CFR2[]={0x01,0x40,0x08,0x20};
	uint8_t PRO[] = {0x3f, 0xff, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00};
	
	AD9910_CSN1_Clr;
	Write_8bit_1(0x00);														// 将CFR1写入其寄存器0x00
	for(j=0;j<4;j++)
	{
		Write_8bit_1(CFR1[j]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	
	AD9910_CSN1_Clr;
	Write_8bit_1(0x01);														// 将CFR2写入其寄存器0x01
	for(j=0;j<4;j++)
	{
		Write_8bit_1(CFR2[j]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	
	AD9910_CSN1_Clr;
	Write_8bit_1(0x0e);														// 将RAM Profile0写入其寄存器0x0e
	for(j=0;j<8;j++)
	{
		Write_8bit_1(PRO[j]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	

	
	AD9910_IUP1_Clr;															// 更新AD9910
	Delay_ns (10);
	AD9910_IUP1_Set;
	Delay_ns (10);
	AD9910_IUP1_Clr;
}
//---------------------------------------------------------------------------------------------------------------------------------
//函数名称:void AD9910_RAM_ZB_Fre_Init(void)
//函数功能:设置RAM模式中的载波的频率的初始化
//入口参数:无
//出口参数:无
//---------------------------------------------------------------------------------------------------------------------------------
void AD9910_RAM_ZB_Fre_Init_1(void)
{
	int j;
	
	uint8_t CFR1[]={0x00,0x40,0x00,0x00};						// 开启AD9910反Sinc滤波功能
	uint8_t CFR2[]={0x00,0x41,0x08,0x20};						// 读取有效的FTW寄存器开启，FTW是写载波频率时用的
	
	AD9910_CSN1_Clr;
	Write_8bit_1(0x00);														// 将CFR1写入其寄存器0x00
	for(j=0;j<4;j++)
	{
		Write_8bit_1(CFR1[j]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	
	AD9910_CSN1_Clr;
	Write_8bit_1(0x01);														// 将CFR2写入其寄存器0x01
	for(j=0;j<4;j++)
	{
		Write_8bit_1(CFR2[j]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	
	
	AD9910_IUP1_Clr;															// 更新AD9910
	Delay_ns (10);
	AD9910_IUP1_Set;
	Delay_ns (10);
	AD9910_IUP1_Clr;
}


//---------------------------------------------------------------------------------------------------------------------------------
//函数名称:void AD9910_RAM_ZB_Fre_Set(uint32_t Freq)
//函数功能:设置RAM模式中的载波的频率
//入口参数:Freq--------------------载波频率
//出口参数:无
//---------------------------------------------------------------------------------------------------------------------------------
void AD9910_RAM_ZB_Fre_Set_1(uint32_t Freq)
{
		uint8_t FTW[]={0x00,0x00,0xa7,0xc6};
		int j;
		uint32_t Temp;  

	  Temp=(uint32_t)Freq*4.294967296;	   						// 将输入频率转化为相应的FTW值  4.294967296=(2^32)/1000000000
		
	  FTW[3]=(uint8_t)Temp;
	  FTW[2]=(uint8_t)(Temp>>8);
		FTW[1]=(uint8_t)(Temp>>16);
	  FTW[0]=(uint8_t)(Temp>>24);
		
		AD9910_CSN1_Clr;														// CSN置0			开片选
		Write_8bit_1(0x07);													// 选择0x07地址           	将频率写入寄存器
		for(j=0;j<4;j++)
		{
			Write_8bit_1(FTW[j]);
		}
		AD9910_CSN1_Set;														// CSN置1			关片选
		Delay_ns (10);
		
		
		AD9910_IUP1_Clr;														// 更新AD9910输出
		Delay_ns (10);
		AD9910_IUP1_Set;
		Delay_ns (10);
		AD9910_IUP1_Clr;
}

