//函数名称:void AD9910_RAM_Fre_W(void)
//函数功能:将数据写入1024*32的RAM中---------------------------频率
//入口参数:无
//出口参数:无
//---------------------------------------------------------------------------------------------------------------------------------
void AD9910_RAM_Fre_W(void)
{
	int j;
	uint8_t CFR1[]={0x00,0x40,0x00,0x00};																	// 开启AD9910反Sinc滤波
	uint8_t CFR2[]={0x00,0x40,0x08,0x20};
	uint8_t RAM_PRO0[]={0x00,0xff,0xff,0xff,0xC0,0x00,0x00,0x00};					// 设置RAM的起始和终止地址、地址步进率
	
	
	AD9910_CSN1_Clr;
	Write_8bit_1(0x00);																									// 将CFR1写入其寄存器0x00
	for(j=0;j<4;j++)
	{
		Write_8bit_1(CFR1[j]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	
	AD9910_CSN1_Clr;
	Write_8bit_1(0x01);																									// 将CFR1写入其寄存器0x00
	for(j=0;j<4;j++)
	{
		Write_8bit_1(CFR2[j]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	
	AD9910_CSN1_Clr;																										// 将RAM的起始和终止地址、地址步进率写入相应的寄存器  0x0e
	Write_8bit_1(0x0e);																
	for(j=0;j<8;j++)
	{
		Write_8bit_1(RAM_PRO0[j]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	
	AD9910_IUP1_Clr;																										// 更新一下AD9910
	Delay_ns (10);
	AD9910_IUP1_Set;
	Delay_ns (10);
	AD9910_IUP1_Clr;
	Delay_ns (10);
	
	AD9910_CSN1_Clr;								
	Write_8bit_1(0x16);														
	for(j=0; j<1024; j++)
	{	
		Write_32bit_1(RAM_Fre[j]);																				// 将频率RAM的内容写入0x16寄存器
	}
		AD9910_CSN1_Set;
	
		AD9910_IUP1_Clr;																									// 在更新一下AD9910
		Delay_ns (10);
		AD9910_IUP1_Set;
		Delay_ns (10);
		AD9910_IUP1_Clr;
		Delay_ns (10);
}

