//------------------------------------------------------------------------------------
//函数名称:void Freq_convert(uint32_t Freq)	
//函数功能:AD9910写初始频率
//入口参数:Freq      写频率   频率小于450M														
//出口参数:无
//------------------------------------------------------------------------------------
void Freq_convert(uint32_t Freq)
{
	  uint32_t Temp;            
	  Temp=(uint32_t)Freq*4.294967296;	   //将输入频率因子分为四个字节  4.294967296=(2^32)/1000000000
		
	  FTW[3]=(uint8_t)Temp;
	  FTW[2]=(uint8_t)(Temp>>8);
		FTW[1]=(uint8_t)(Temp>>16);
	  FTW[0]=(uint8_t)(Temp>>24);
}
//------------------------------------------------------------------------------------
//函数名称:void Amp_convert(uint32_t Amp)	
//函数功能:AD9910写初始幅度
//入口参数:Amp      写幅度  														
//出口参数:无
//------------------------------------------------------------------------------------
void Amp_convert(uint32_t Amp)
{
		
	  ASF[3]=(uint8_t)Amp;
	  ASF[2]=(uint8_t)(Amp>>8);

}
//------------------------------------------------------------------------------------
//函数名称:void AD9910_Init_Sin(void)
//函数功能:AD9910时钟的设置和辅助DAC设置 以及AD9910并行正弦初始化
//入口参数:无
//出口参数:无
//------------------------------------------------------------------------------------
void AD9910_Init_Sin(int gain)
{
	int j;
	AD9910_PF01_Clr;														// 选择 Profile0
	AD9910_PF1_1_Clr;
	AD9910_PF2_1_Clr;
	AD9910_DRH1_Clr;
	AD9910_DRC1_Clr;
	AD9910_MRT1_Set;														// 复位AD9910
	AD9910_MRT1_Clr;
	
	AD9910_CSN1_Clr;														// CSN置0			开片选
	Write_8bit_1(0x00);													// 选择0x00地址            CFR1寄存器写入数据
	for(j=0;j<4;j++)
	{
		Write_8bit_1(CFR1[j]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);
	AD9910_CSN1_Clr;														// CSN置1			关片选
	
	AD9910_CSN1_Clr;														// CSN置0			开片选
	
	Write_8bit_1(0x01);													// 选择0x01地址            CFR2寄存器写入数据
	CFR2[3] += gain;
	for(j=0;j<4;j++)
	{
		Write_8bit_1(CFR2[j]);
	}
	AD9910_CSN1_Set;	
	Delay_ns (10);	
	CFR2[3] = 0x30;
	AD9910_CSN1_Clr;														// CSN置0			开片选
	
	Write_8bit_1(0x02);													// 选择0x02地址            CFR3寄存器写入数据
	for(j=0;j<4;j++)
	{
		Write_8bit_1(CFR3[j]);	
	}
	AD9910_CSN1_Set;														// CSN置1			关片选
	Delay_ns (10);
	
	AD9910_CSN1_Clr;														// CSN置0			开片选
	Write_8bit_1(0x03);													// 选择0x03地址            辅助DAC寄存器写入数据
	for(j=0;j<4;j++)
	{
		Write_8bit_1(Assist_DAC[j]);
	}
	AD9910_CSN1_Set;														// CSN置1			关片选
	Delay_ns (10);
	
	AD9910_CSN1_Clr;														// CSN置0			开片选
	Write_8bit_1(0x07);													// 选择0x07地址           	将初始频率写入寄存器
	for(j=0;j<4;j++)
	{
		Write_8bit_1(FTW[j]);
	}
	AD9910_CSN1_Set;														// CSN置1			关片选
	Delay_ns (10);
	
	AD9910_IUP1_Clr;
	Delay_ns (10);
	AD9910_IUP1_Set;
	Delay_ns (10);
	AD9910_IUP1_Clr;
}
