void AD9910_LinearASF_Test()
{
    uint16_t asf_value;
    uint32_t freq = 1000000;  
    uint16_t phase = 0;

    for (asf_value = 0x0100; asf_value <= 0x3FFF; asf_value += 0x0100)  
    {
        AD9910_Singal_Profile_Set_1(0, freq, asf_value, phase);

    }
		
}

void AD9910_FrequencySweep(uint32_t start_freq, uint32_t freq_step,uint16_t Amp,uint16_t phase)
{
    uint32_t freq = start_freq;

    while (freq >= 1 && freq <= 450000000)
    {
        AD9910_Singal_Profile_Set_1(0, freq, Amp, phase);
        freq += freq_step;
    }
}

void AD9910_IUP()
{
		AD9910_IUP1_Clr;
		Delay_ns (10);																									// 更新AD9910
		AD9910_IUP1_Set;
		Delay_ns (10);
		AD9910_IUP1_Clr;
		Delay_ns (10);	


}

